import{_ as t}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{c as o,o as a,ad as r}from"./chunks/mermaid.Cb40Nz1P.js";import"./chunks/cytoscape.C2CwDKBM.js";import"./chunks/dayjs.C32PoDnw.js";const m=JSON.parse('{"title":"Connectors 连接器","description":"","frontmatter":{},"headers":[],"relativePath":"zh/products/ai-coding/claude/connectors.md","filePath":"zh/products/ai-coding/claude/connectors.md"}'),l={name:"zh/products/ai-coding/claude/connectors.md"};function n(i,e,s,c,d,u){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="connectors-连接器" tabindex="-1">Connectors 连接器 <a class="header-anchor" href="#connectors-连接器" aria-label="Permalink to &quot;Connectors 连接器&quot;">​</a></h1><blockquote><p>Connectors 让 Claude 直接接入你的应用和服务——读取数据、执行操作、触发工作流——全部在对话中完成，无需切换工具。这是将 Claude 从&quot;问答助手&quot;升级为&quot;执行代理&quot;的核心能力。</p></blockquote><h2 id="什么是-connectors" tabindex="-1">什么是 Connectors <a class="header-anchor" href="#什么是-connectors" aria-label="Permalink to &quot;什么是 Connectors&quot;">​</a></h2><p>Connector（连接器）是 Claude 与外部服务之间的授权通道。连接后，你可以在对话中直接让 Claude：</p><ul><li>在 Gmail 里搜索邮件、起草回复</li><li>在 Google Calendar 上查看空档、新建会议</li><li>在 Notion 里创建或更新页面</li><li>在 Linear / GitHub 里提 Issue、查看 PR</li><li>在 Slack 里发消息、搜索历史记录</li></ul><p><strong>底层实现</strong>：Connectors 基于 <a href="https://code.claude.com/docs/zh-CN/build-with-claude/mcp" target="_blank" rel="noreferrer">Remote MCP（Model Context Protocol）</a>构建，每个连接器本质上是一个运行在云端的 MCP 服务器，向 Claude 暴露一组工具（Tools）。</p><p><strong>适用范围</strong>：claude.ai 网页版、iOS/Android App、Claude Desktop（Cowork 和 Code 标签）、Claude Code CLI、API。</p><hr><h2 id="连接器类型" tabindex="-1">连接器类型 <a class="header-anchor" href="#连接器类型" aria-label="Permalink to &quot;连接器类型&quot;">​</a></h2><h3 id="预置连接器-pre-built-connectors" tabindex="-1">预置连接器（Pre-built Connectors） <a class="header-anchor" href="#预置连接器-pre-built-connectors" aria-label="Permalink to &quot;预置连接器（Pre-built Connectors）&quot;">​</a></h3><p>官方内置，一键授权即用，无需配置。目前已有 50+ 个，覆盖以下类别：</p><table tabindex="0"><thead><tr><th>类别</th><th>代表服务</th><th>核心能力</th></tr></thead><tbody><tr><td><strong>Google Workspace</strong></td><td>Gmail、Google Calendar、Google Drive</td><td>读邮件/起草、查日程/建会议、搜索文件</td></tr><tr><td><strong>Microsoft 365</strong></td><td>Outlook、Teams、SharePoint、OneDrive</td><td>搜索邮件/文档、查看会议、浏览 Teams 消息</td></tr><tr><td><strong>项目管理</strong></td><td>Linear、Asana、Jira、Notion</td><td>创建/查询 Issue、更新任务、搜索页面</td></tr><tr><td><strong>代码托管</strong></td><td>GitHub</td><td>查看 PR、搜索代码、创建 Issue</td></tr><tr><td><strong>沟通协作</strong></td><td>Slack</td><td>发消息、搜索历史、读取频道</td></tr><tr><td><strong>设计工具</strong></td><td>Canva、Figma</td><td>查看设计文件（部分支持交互渲染）</td></tr><tr><td><strong>CRM / 销售</strong></td><td>Salesforce、HubSpot</td><td>查询记录、更新联系人</td></tr></tbody></table><blockquote><p><strong>Interactive 标记</strong>：部分连接器支持在对话中直接渲染动态界面（看板、仪表盘、设计稿预览），而不仅是文字回答。</p></blockquote><h3 id="自定义连接器-custom-connectors-remote-mcp" tabindex="-1">自定义连接器（Custom Connectors / Remote MCP） <a class="header-anchor" href="#自定义连接器-custom-connectors-remote-mcp" aria-label="Permalink to &quot;自定义连接器（Custom Connectors / Remote MCP）&quot;">​</a></h3><p>如果你的工具没有预置连接器，可以自己搭建：</p><ol><li>开发一个遵循 MCP 协议的服务器（支持 HTTP + SSE）</li><li>部署到<strong>公网可访问</strong>的地址（Anthropic 云端需要能 reach 到它）</li><li>在 Claude 设置中填入你的 MCP Server URL 和 OAuth 凭证</li><li>完成后即可在对话中使用你自定义的工具</li></ol><blockquote><p>内网服务需要将 Anthropic 的出口 IP 加入防火墙白名单。参考 <a href="https://code.claude.com/docs/zh-CN/build-with-claude/mcp" target="_blank" rel="noreferrer">Remote MCP 开发文档</a>。</p></blockquote><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="步骤一-进入连接器目录" tabindex="-1">步骤一：进入连接器目录 <a class="header-anchor" href="#步骤一-进入连接器目录" aria-label="Permalink to &quot;步骤一：进入连接器目录&quot;">​</a></h3><p><strong>路径 A（对话内）</strong>：点击对话框左下角的 <strong><code>+</code></strong> 按钮 → 选择 <strong>Connectors</strong></p><p><strong>路径 B（设置页）</strong>：<code>Settings → Customize → Connectors</code> → 浏览目录</p><h3 id="步骤二-连接服务" tabindex="-1">步骤二：连接服务 <a class="header-anchor" href="#步骤二-连接服务" aria-label="Permalink to &quot;步骤二：连接服务&quot;">​</a></h3><ol><li>找到目标连接器，点击查看其能力说明和读/写权限详情</li><li>点击 <strong>Connect</strong>（预置）或 <strong>Install</strong>（远程 MCP）</li><li>完成 OAuth 授权流程（跳转到对应服务的登录页）</li><li>授权完成后，连接器出现在你的已安装列表</li></ol><h3 id="步骤三-在对话中启用" tabindex="-1">步骤三：在对话中启用 <a class="header-anchor" href="#步骤三-在对话中启用" aria-label="Permalink to &quot;步骤三：在对话中启用&quot;">​</a></h3><p>连接器安装后<strong>不会自动在所有对话中激活</strong>。在需要使用的对话里：</p><ul><li>点击 <strong><code>+</code></strong> 按钮，勾选要启用的连接器</li><li>或者直接描述任务——Claude 会提示你是否启用相关连接器</li></ul><h3 id="步骤四-直接描述任务" tabindex="-1">步骤四：直接描述任务 <a class="header-anchor" href="#步骤四-直接描述任务" aria-label="Permalink to &quot;步骤四：直接描述任务&quot;">​</a></h3><p>连接器激活后，用自然语言表达需求即可：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我查一下本周 Gmail 里来自 acme.com 的邮件，</span></span>
<span class="line"><span>提取所有提到交货日期的内容，</span></span>
<span class="line"><span>然后在 Notion 里新建一个&quot;Acme 跟进&quot;页面记录下来。</span></span></code></pre></div><p>Claude 会自动调用 Gmail 连接器搜索邮件，再调用 Notion 连接器创建页面。</p><hr><h2 id="主要连接器详解" tabindex="-1">主要连接器详解 <a class="header-anchor" href="#主要连接器详解" aria-label="Permalink to &quot;主要连接器详解&quot;">​</a></h2><h3 id="google-workspace" tabindex="-1">Google Workspace <a class="header-anchor" href="#google-workspace" aria-label="Permalink to &quot;Google Workspace&quot;">​</a></h3><p><strong>Gmail</strong></p><ul><li>用自然语言搜索邮件（&quot;上周 Alice 发给我关于预算的邮件&quot;）</li><li>起草邮件（Claude 生成草稿，<strong>需要你手动发送</strong>，Claude 不能代为发送）</li><li>读取附件信息、管理标签和线程</li><li>列出已保存草稿</li></ul><p><strong>Google Calendar</strong></p><ul><li>查看个人和共享日历的事件</li><li>新建、编辑、删除活动，支持设置重复规则</li><li>查找多位参与者的共同空档</li><li>管理受邀人列表、响应邀请</li></ul><p><strong>Google Drive</strong></p><ul><li>搜索并检索文档内容（仅提取文本，不处理图片）</li><li>将文档添加到当前对话或 Project</li><li>查看文件权限和最近变更</li><li>将 Claude 生成的文件直接保存到 Drive（需开启代码执行）</li></ul><h3 id="microsoft-365" tabindex="-1">Microsoft 365 <a class="header-anchor" href="#microsoft-365" aria-label="Permalink to &quot;Microsoft 365&quot;">​</a></h3><p>以<strong>只读</strong>方式访问，Claude 可以检索和分析，但<strong>不能修改、删除或新建</strong>内容：</p><ul><li><strong>Outlook</strong>：搜索邮件线程，跟踪项目进展和客户反馈</li><li><strong>Teams</strong>：读取你参与的频道消息和聊天记录</li><li><strong>SharePoint / OneDrive</strong>：跨站点搜索并分析文档</li><li><strong>Calendar</strong>：读取会议摘要和参与者信息，为即将到来的会议做准备</li></ul><h3 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h3><ul><li>搜索代码库、查看文件内容</li><li>创建 Issue、查看 PR 状态和评论</li><li>搜索提交历史</li></ul><blockquote><p>Claude Code 用户注意：CLI 里通过 MCP 连接 GitHub 功能更全，支持创建 PR、合并等写操作。</p></blockquote><h3 id="slack" tabindex="-1">Slack <a class="header-anchor" href="#slack" aria-label="Permalink to &quot;Slack&quot;">​</a></h3><ul><li>搜索频道历史消息</li><li>发送消息到指定频道或 DM（<strong>需要你确认后执行</strong>）</li><li>读取线程回复</li></ul><h3 id="linear-asana-jira" tabindex="-1">Linear / Asana / Jira <a class="header-anchor" href="#linear-asana-jira" aria-label="Permalink to &quot;Linear / Asana / Jira&quot;">​</a></h3><ul><li>创建、查询、更新 Issue 和任务</li><li>搜索项目看板</li><li>获取 Sprint 状态</li></ul><hr><h2 id="连接器与-projects-组合使用" tabindex="-1">连接器与 Projects 组合使用 <a class="header-anchor" href="#连接器与-projects-组合使用" aria-label="Permalink to &quot;连接器与 Projects 组合使用&quot;">​</a></h2><p>连接器在 <strong>Projects</strong> 里使用效果最佳：</p><ol><li>在 Project 里连接 Google Drive，Claude 可持续访问该项目的所有文档</li><li>在 Project 里连接 Linear，Claude 记住项目的 Issue 规范和优先级标准</li><li>结合 Project 的自定义指令，统一工作流规范</li></ol><p><strong>示例</strong>：创建一个&quot;Q2 产品规划&quot;Project，连接 Google Drive（需求文档）+ Linear（任务管理），让 Claude 成为能同时读取需求并同步创建任务的项目助手。</p><hr><h2 id="连接器-定期任务" tabindex="-1">连接器 + 定期任务 <a class="header-anchor" href="#连接器-定期任务" aria-label="Permalink to &quot;连接器 + 定期任务&quot;">​</a></h2><p>连接器可以和<a href="./cowork.html#定期任务自动化">定期任务</a>配合，实现自动化工作流：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每周一早上 9 点：</span></span>
<span class="line"><span>- 读取上周 Gmail 里的客户邮件（Gmail 连接器）</span></span>
<span class="line"><span>- 汇总关键问题和待处理事项</span></span>
<span class="line"><span>- 在 Notion 创建&quot;客户周报&quot;页面（Notion 连接器）</span></span>
<span class="line"><span>- 发送 Slack 通知给团队（Slack 连接器）</span></span></code></pre></div><p>云端定期任务（通过 <code>/schedule</code> 创建）会携带你已授权的连接器权限，无需电脑开机。</p><hr><h2 id="权限与安全" tabindex="-1">权限与安全 <a class="header-anchor" href="#权限与安全" aria-label="Permalink to &quot;权限与安全&quot;">​</a></h2><h3 id="权限模型" tabindex="-1">权限模型 <a class="header-anchor" href="#权限模型" aria-label="Permalink to &quot;权限模型&quot;">​</a></h3><ul><li><strong>每个连接器独立授权</strong>：连接 Gmail 不等于授权 Calendar，各服务单独 OAuth</li><li><strong>最小权限原则</strong>：Claude 只能访问你账户中你自己有权限访问的内容</li><li><strong>读/写区分</strong>：连接器详情页明确标注哪些操作是只读、哪些会写入数据</li><li><strong>操作前确认</strong>：涉及写操作（发消息、创建 Issue、修改日历）Claude 会在执行前展示操作计划</li></ul><h3 id="团队和企业注意" tabindex="-1">团队和企业注意 <a class="header-anchor" href="#团队和企业注意" aria-label="Permalink to &quot;团队和企业注意&quot;">​</a></h3><ul><li><strong>Team / Enterprise</strong> 计划：组织 Owner 需要在 <strong>Organization Settings</strong> 中先启用 Connectors 功能，成员才能授权使用</li><li><strong>数据传输</strong>：所有连接器数据传输均加密</li><li><strong>断开连接</strong>：随时可以在 <code>Settings → Connectors</code> 中撤销某个服务的授权</li></ul><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h3><ul><li>定期检查已连接的服务，断开不再使用的连接器</li><li>不要在共享 Project 中开启包含个人邮件的连接器（其他成员可能触发查询）</li><li>对于包含敏感数据的服务（如财务系统），使用专用账号而非个人主账号授权</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：Connectors 需要额外付费吗？</strong></p><p>不需要。Connectors 功能包含在 Pro（及以上）订阅中，无额外费用。</p><p><strong>Q：连接器能访问我在服务里所有的数据吗？</strong></p><p>只能访问你自己有权限访问的数据。连接 Google Drive 后，Claude 只能读取你有访问权限的文件，无法绕过原服务的权限控制。</p><p><strong>Q：Claude 会不会在我不知情的情况下自动操作我的服务？</strong></p><p>不会。涉及写操作（发邮件草稿、创建事件、发 Slack 消息）时，Claude 会先展示操作计划并等待你确认。</p><p><strong>Q：我的公司内网系统能接入 Connectors 吗？</strong></p><p>可以，通过自定义 Remote MCP 实现，但你的 MCP 服务器需要是公网可访问的（或将 Anthropic 出口 IP 加入白名单）。</p><p><strong>Q：连接器在 Claude Code CLI 里如何使用？</strong></p><p>Claude Code 通过 MCP 集成（<code>claude mcp add</code>）连接工具，与 claude.ai 的 Connectors UI 是两套入口，但底层协议相同。参见 <a href="./claude-code.html#第六部分mcp-集成">MCP 集成章节</a>。</p><hr><h2 id="资源" tabindex="-1">资源 <a class="header-anchor" href="#资源" aria-label="Permalink to &quot;资源&quot;">​</a></h2><ul><li><a href="https://support.claude.com/en/articles/10168395-set-up-claude-integrations" target="_blank" rel="noreferrer">连接器设置指南</a></li><li><a href="https://support.claude.com/en/articles/10166901-use-google-workspace-connectors" target="_blank" rel="noreferrer">Google Workspace 连接器</a></li><li><a href="https://support.claude.com/en/articles/12542951-enable-and-use-the-microsoft-365-connector" target="_blank" rel="noreferrer">Microsoft 365 连接器</a></li><li><a href="https://support.claude.com/en/articles/11175166-get-started-with-custom-connectors-using-remote-mcp" target="_blank" rel="noreferrer">自定义 Remote MCP 连接器</a></li><li><a href="https://support.claude.com/en/articles/11176164-pre-built-web-connectors-using-remote-mcp" target="_blank" rel="noreferrer">预置 Web 连接器列表</a></li><li><a href="https://support.claude.com/en/collections/15399129-connectors" target="_blank" rel="noreferrer">Connectors 完整集合</a></li></ul>`,83)])])}const C=t(l,[["render",n]]);export{m as __pageData,C as default};
